import java.util.*;
import java.lang.*;
import java.io.*;

import java.util.Scanner;

class LinkedList {
    // Definition of the node structure
    static class Node {
        int data;
        Node next;

        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    // Recursive function to reverse the linked list
    static Node reverseRecursive(Node head) {
        // Base case: if the list is empty or has only one node
        if (head == null || head.next == null) {
            return head;
        }

        // Recursive case: reverse the rest of the list
        Node rest = reverseRecursive(head.next);

        // Make the current node the last node of the reversed list
        head.next.next = head;
        head.next = null;

        return rest;  // Return the new head of the reversed list
    }

    // Function to print the linked list
    static void printList(Node head) {
        Node temp = head;
        while (temp != null) {
            System.out.print(temp.data);
            if (temp.next != null) {
                System.out.print(" -> ");
            }
            temp = temp.next;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        Node head = null;
        Node temp = null;

        // Handle edge case where no nodes are given
        if (n == 0) {
            System.out.println("NULL");
            return;
        }

        // Input the data for each node
        for (int i = 0; i < n; i++) {
            int data = sc.nextInt();
            Node new_node = new Node(data);

            if (head == null) {
                head = new_node;  // First node becomes the head
            } else {
                temp.next = new_node;  // Link the new node to the previous one
            }
            temp = new_node;  // Move temp to the new node
        }

        // Reversing the list recursively
        head = reverseRecursive(head);

        // Print the reversed linked list
        printList(head);
    }
}
